import{_ as n,o,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F15_關係人交易與利益輸送風險_財務分析專家.md","filePath":"32Ｑ題本＿重要/財務組/F15_關係人交易與利益輸送風險_財務分析專家.md"}'),a={name:"32Ｑ題本＿重要/財務組/F15_關係人交易與利益輸送風險_財務分析專家.md"};function i(s,t,e,g,_,c){return o(),l("div",null,[...t[0]||(t[0]=[r('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f15-關係人交易與利益輸送風險" tabindex="-1">F15: 關係人交易與利益輸送風險 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F15</li><li><strong>題目：</strong> 是否存在異常大額的關係人交易（連屬公司、子公司）？其定價是否符合市場行情？是否存在利益輸送或虛增利潤之嫌？</li><li><strong>推薦專家：</strong> 財務分析專家 (<code>finance-financial-analyst</code>)</li><li><strong>推薦理由：</strong> 專精於「審計與公司治理」及「舞弊偵測」。具備從分部資訊（Segment Information）中識別異常交易流向的能力，能穿透複雜的交叉持股關係，判定資金往來是否具備「商業實質」，是守護股東權益的防線。</li><li><strong>意圖：</strong> 執行「關聯交易與治理透明度審計」。判定公司是否透過子公司進行「利潤調節」或「負債隱藏」，識別不具備公平市場定價之交易，預警潛在的利益輸送風險。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心事實來源：Annual Report (年報)】</strong>：必須查閱「財務報告附註 -&gt; 關係人交易」章節。詳列所有應收/應付關係人款項及銷貨/進貨明細。</li><li><strong>【外部驗證：Web Search】</strong>：檢索「[公司名] 子公司 掏空」、「[公司名] 關係人 訴訟」。</li><li><strong>【穿透校準：MOPS】</strong>：查閱「兩岸投資資訊」或「海外子公司營運狀況」，比對子公司之利潤率是否異常高於母公司。</li></ol></li><li><strong>邏輯：</strong> 執行「利潤分佈背離測試」——若虧損的子公司仍有大量採購或母公司給予極長帳期，判定為「利益輸送」或「資產減損掩飾」；執行「定價公平性分析」。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>年報提取</strong>：用 <code>pdf</code> 工具從年報提取「關係人交易附註」</li><li><strong>分析</strong>：關係人銷貨佔比、關係人應收款項、資金貸與、背書保證</li><li><strong>判讀</strong>：關係人交易佔營收 &gt;5% 需警惕；&gt;10% = 利益輸送風險</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①答詢詳解 ≥200 字、專家評析 ≥200 字；②空頭視角 ≥2 個（股權集中、獨董不足是重要利空）</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【交易規模實測】</strong>：智慧體<strong>必須</strong>列出「關係人交易佔營收/成本之百分比」。若比例超過 20% 且無合理解釋，必須標註為「高治理風險」。</li><li><strong>【帳期異常偵測】</strong>：比對關係人應收款項與一般客戶之週轉率。若關係人收款天數顯著拉長（例如超過 180 天），必須判定為「資金占用風險」。</li><li><strong>【子公司利潤滲透】</strong>：分析子公司是否淪為母公司的「垃圾桶（承接不良資產）」或「小金庫（虛增利潤）」。</li><li><strong>【描述指標】</strong>：絕對禁用「往來正常」、「合作緊密」。必須量化為具體的「關係人應收款金額」、「與關係人往來之毛利率階差」與「分部獲利貢獻比」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f15-專家答詢】財務分析專家-finance-financial-analyst" tabindex="-1">【F15 專家答詢】財務分析專家 (finance-financial-analyst) <a class="header-anchor" href="#【f15-專家答詢】財務分析專家-finance-financial-analyst" aria-label="Permalink to &quot;【F15 專家答詢】財務分析專家 (finance-financial-analyst)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「交易佔比+定價公平性判定」結構（例：關係人進貨佔 X%，帳期較一般供應商 [拉長/縮短]，定價 [符合/偏離] 行情，治理風險等級為 [低/中/高]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：關係人交易比例極低（&lt; 5%），且往來條件完全對齊市場第三方，透明度高。</li><li><strong>A (良)</strong>：具備產業鏈整合之深度的關係人往來，但定價機制透明且經外部稽核確認具備商業合理性。</li><li><strong>B (持平)</strong>：高度依賴特定關係人進行採購或銷貨，且往來餘額持續攀升，缺乏公平定價證據，具備高度利益輸送與財報粉飾風險。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註年報附註 P.XXX 之關係人交易彙總表。</li></ul>',12)])])}const h=n(a,[["render",i]]);export{f as __pageData,h as default};
